noncompliant:
// Defining macros within blocks
void function() {
  #define TEMP_BUFFER_SIZE 256 // Non-compliant
  char buffer[TEMP_BUFFER_SIZE];
  // ...
  #undef TEMP_BUFFER_SIZE // Non-compliant
}

// In namespace (C++)
namespace MyNamespace {
  #define MY_CONSTANT 42 // Non-compliant
  #undef OLD_MACRO // Non-compliant
}

compliant:
// Define macros at global scope
#define TEMP_BUFFER_SIZE 256

void function() {
  char buffer[TEMP_BUFFER_SIZE];
  // ...
}

#undef TEMP_BUFFER_SIZE

// Or use constants instead
static const int BUFFER_SIZE = 256;

void function() {
  char buffer[BUFFER_SIZE];
  // ...
}
